// ==================== GPS TRACKING HOOK ====================
const useGPSTracking = (user, intervaloMin = 5) => {
  const [posicion, setPosicion] = useState(null);
  const [gpsError, setGpsError] = useState(null);
  const [gpsActivo, setGpsActivo] = useState(false);

  const enviarPing = (coords) => {
    if (!user) return;
    fetch(`${API_URL}/gps/ping`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        username: user.username || user.user,
        nombre: user.nombre || user.username,
        lat: coords.latitude,
        lng: coords.longitude,
        precision: coords.accuracy
      })
    }).catch(() => {});
  };

  useEffect(() => {
    if (!navigator.geolocation) { setGpsError("GPS no disponible"); return; }
    setGpsActivo(true);
    // Ping inmediato
    navigator.geolocation.getCurrentPosition(
      pos => { setPosicion(pos.coords); enviarPing(pos.coords); setGpsError(null); },
      err => { setGpsError("Permiso GPS denegado"); setGpsActivo(false); }
    );
    // Ping cada N minutos
    const iv = setInterval(() => {
      navigator.geolocation.getCurrentPosition(
        pos => { setPosicion(pos.coords); enviarPing(pos.coords); setGpsError(null); },
        () => {}
      );
    }, intervaloMin * 60 * 1000);
    return () => clearInterval(iv);
  }, [user?.username]);

  return { posicion, gpsError, gpsActivo };
};

// ==================== MAPA OPERARIOS ====================
const MapaOperarios = ({ user }) => {
  const mapRef = useRef(null);
  const mapInstanceRef = useRef(null);
  const markersRef = useRef({});
  const [operarios, setOperarios] = useState([]);
  const [selOp, setSelOp] = useState(null);
  const [loading, setLoading] = useState(false);
  const [lastUpdate, setLastUpdate] = useState(null);
  const [recorrido, setRecorrido] = useState([]);
  const [recorridoOp, setRecorridoOp] = useState(null);
  const recorridoLayerRef = useRef(null);
  // Historico
  const [modoMapa, setModoMapa] = useState("vivo"); // "vivo" | "historico"
  const [histFecha, setHistFecha] = useState(new Date(new Date().getTime() - 86400000).toISOString().split("T")[0]);
  const [histNombre, setHistNombre] = useState("");
  const [histPlaca, setHistPlaca] = useState("");
  const [histResultados, setHistResultados] = useState([]);
  const [histLoading, setHistLoading] = useState(false);
  const histLayersRef = useRef([]);
  const [personal, setPersonal] = useState([]);
  const [vehiculos, setVehiculos] = useState([]);

  useEffect(() => {
    fetch(`${API_URL}/personal`).then(r=>r.json()).then(d=>setPersonal(Array.isArray(d)?d:[])).catch(()=>{});
    fetch(`${API_URL}/vehiculos`).then(r=>r.json()).then(d=>setVehiculos(Array.isArray(d)?d:[])).catch(()=>{});
  }, []);
  const { posicion, gpsError, gpsActivo } = useGPSTracking(user, 5);

  const MARCA_CONFIG = {
    "INGRESO":  { color:"#06D6A0", label:"Inicio Jornada", order:1 },
    "ALMUERZO": { color:"#F59E0B", label:"Almuerzo",       order:2 },
    "RETORNO":  { color:"#00B4D8", label:"Retorno",        order:3 },
    "CIERRE":   { color:"#8B5CF6", label:"Cierre",         order:4 },
  };

  const cargarRecorrido = async (op) => {
    setRecorridoOp(op);
    try {
      const r = await fetch(`${API_URL}/gps/recorrido/${encodeURIComponent(op.nombre)}`);
      const d = await r.json();
      setRecorrido(Array.isArray(d) ? d : []);
      dibujarRecorrido(Array.isArray(d) ? d : [], op);
    } catch {}
  };

  const dibujarRecorrido = (puntos, op) => {
    const L = window.L;
    const map = mapInstanceRef.current;
    if (!L || !map) return;

    // Clear previous recorrido layer
    if (recorridoLayerRef.current) {
      recorridoLayerRef.current.forEach(l => map.removeLayer(l));
    }

    if (puntos.length === 0) return;

    const layers = [];
    const coords = puntos.map(p => [p.lat, p.lng]);

    // Draw dashed polyline route
    const polyline = L.polyline(coords, {
      color: "#00B4D8", weight: 3, opacity: 0.8,
      dashArray: "8, 6", lineCap: "round"
    }).addTo(map);
    layers.push(polyline);

    // Draw each marca as a pin
    puntos.forEach((p, i) => {
      const cfg = MARCA_CONFIG[p.tipo] || { color:"#94A3B8", label:p.tipo };
      const isFirst = i === 0;
      const isLast = i === puntos.length - 1;

      const iconHtml = `
        <div style="
          position:relative; display:flex;
          flex-direction:column; align-items:center;
        ">
          <div style="
            width:36px; height:36px; border-radius:50%;
            background:${cfg.color}; border:3px solid white;
            box-shadow:0 2px 12px ${cfg.color}80;
            display:flex; align-items:center; justify-content:center;
            font-weight:900; font-size:11px; color:white; font-family:sans-serif;
            z-index:2; position:relative;
          ">${i+1}</div>
          <div style="
            width:2px; height:10px; background:${cfg.color}; opacity:0.6;
          "></div>
        </div>
      `;

      const icon = L.divIcon({ html:iconHtml, className:"", iconSize:[36,46], iconAnchor:[18,46] });

      const marker = L.marker([p.lat, p.lng], { icon, zIndexOffset: 500 })
        .addTo(map)
        .bindPopup(L.popup({ maxWidth:200 }).setContent(`
          <div style="font-family:sans-serif; padding:4px;">
            <div style="
              display:inline-block; padding:3px 10px; border-radius:10px;
              background:${cfg.color}20; color:${cfg.color};
              font-size:11px; font-weight:800; margin-bottom:6px;
            ">${cfg.label}</div>
            <div style="font-weight:700; font-size:13px;">${op.nombre}</div>
            <div style="font-size:12px; color:#6B7A8D;">Hora: ${p.hora}</div>
            ${p.placa ? `<div style="font-size:11px;color:#6B7A8D;">Vehiculo: ${p.placa}</div>` : ""}
            ${p.es_extra ? `<div style="font-size:11px;color:#EF4444;font-weight:700;">Hora extra: ${p.minutos_extra} min</div>` : ""}
            <a href="https://www.google.com/maps?q=${p.lat},${p.lng}" target="_blank"
              style="font-size:11px;color:#00B4D8;text-decoration:none;font-weight:600;display:block;margin-top:6px;">
              Ver ubicacion
            </a>
          </div>
        `));
      layers.push(marker);
    });

    recorridoLayerRef.current = layers;

    // Fit map to recorrido
    try { map.fitBounds(polyline.getBounds(), { padding:[40,40], maxZoom:16 }); } catch {}
  };

  const limpiarRecorrido = () => {
    const map = mapInstanceRef.current;
    if (recorridoLayerRef.current && map) {
      recorridoLayerRef.current.forEach(l => map.removeLayer(l));
      recorridoLayerRef.current = null;
    }
    setRecorrido([]);
    setRecorridoOp(null);
  };

  const COLORES_OP = ["#06D6A0","#00B4D8","#F59E0B","#8B5CF6","#EF4444","#EC4899","#14B8A6","#F97316"];

  const limpiarHistorico = () => {
    const map = mapInstanceRef.current;
    if (histLayersRef.current?.length && map) {
      histLayersRef.current.forEach(l => map.removeLayer(l));
      histLayersRef.current = [];
    }
    setHistResultados([]);
  };

  const buscarHistorico = async () => {
    setHistLoading(true);
    limpiarHistorico();
    try {
      const params = new URLSearchParams({ fecha: histFecha });
      if (histNombre) params.append("nombre", histNombre);
      if (histPlaca) params.append("placa", histPlaca);
      const r = await fetch(`${API_URL}/gps/historico?${params}`);
      const d = await r.json();
      const resultado = Array.isArray(d) ? d : [];
      setHistResultados(resultado);
      dibujarHistorico(resultado);
    } catch {}
    setHistLoading(false);
  };

  const dibujarHistorico = (grupos) => {
    const L = window.L;
    const map = mapInstanceRef.current;
    if (!L || !map) return;
    const allLayers = [];
    const allBounds = [];

    grupos.forEach((grupo, gi) => {
      const color = COLORES_OP[gi % COLORES_OP.length];
      const puntos = grupo.marcaciones;
      if (puntos.length === 0) return;
      const coords = puntos.map(p => [p.lat, p.lng]);

      // Polyline per operario
      const poly = L.polyline(coords, {
        color, weight: 3, opacity: 0.85, dashArray: "8,5", lineCap: "round"
      }).addTo(map);
      allLayers.push(poly);
      coords.forEach(c => allBounds.push(c));

      // Markers per marcacion
      puntos.forEach((p, i) => {
        const mc = MARCA_CONFIG[p.tipo] || { color, label: p.tipo };
        const iconHtml = `<div style="
          width:32px;height:32px;border-radius:50%;
          background:${mc.color};border:3px solid white;
          box-shadow:0 2px 10px ${mc.color}80;
          display:flex;align-items:center;justify-content:center;
          font-weight:900;font-size:10px;color:white;font-family:sans-serif;">
          ${i+1}
        </div>`;
        const icon = L.divIcon({ html: iconHtml, className:"", iconSize:[32,32], iconAnchor:[16,16] });
        const marker = L.marker([p.lat, p.lng], { icon }).addTo(map)
          .bindPopup(L.popup({ maxWidth:200 }).setContent(`
            <div style="font-family:sans-serif;padding:4px;">
              <div style="font-weight:800;font-size:13px;color:${color}">${grupo.nombre}</div>
              <div style="display:inline-block;padding:2px 8px;border-radius:8px;
                background:${mc.color}20;color:${mc.color};font-size:11px;font-weight:700;margin:4px 0;">
                ${mc.label}
              </div>
              <div style="font-size:11px;color:#6B7A8D;">Hora: ${p.hora}</div>
              ${p.placa ? `<div style="font-size:11px;color:#6B7A8D;">Vehiculo: ${p.placa}</div>`:""}
              <a href="https://www.google.com/maps?q=${p.lat},${p.lng}" target="_blank"
                style="font-size:11px;color:#00B4D8;text-decoration:none;font-weight:600;display:block;margin-top:4px;">
                Ver ubicacion
              </a>
            </div>
          `));
        allLayers.push(marker);
      });
    });

    histLayersRef.current = allLayers;
    if (allBounds.length > 0) {
      try { map.fitBounds(allBounds, { padding:[40,40], maxZoom:15 }); } catch {}
    }
  };

  const estadoConfig = {
    "INGRESO":    { color: "#06D6A0", label: "En Jornada",  pulse: true  },
    "ALMUERZO":   { color: "#F59E0B", label: "Almuerzo",    pulse: false },
    "RETORNO":    { color: "#00B4D8", label: "Trabajando",  pulse: true  },
    "CIERRE":     { color: "#8B5CF6", label: "Finalizo",    pulse: false },
    "SIN MARCAR": { color: "#94A3B8", label: "Sin iniciar", pulse: false },
  };

  const cargarOperarios = async () => {
    setLoading(true);
    try {
      const r = await fetch(`${API_URL}/gps/activos`);
      const d = await r.json();
      setOperarios(Array.isArray(d) ? d : []);
      setLastUpdate(new Date());
    } catch {}
    setLoading(false);
  };

  // Init Leaflet map
  useEffect(() => {
    if (mapInstanceRef.current) return;
    const L = window.L;
    if (!L || !mapRef.current) return;

    const map = L.map(mapRef.current, {
      center: [4.711, -74.0721], zoom: 12,
      zoomControl: true, attributionControl: false,
      dragging: true, touchZoom: true,
      scrollWheelZoom: true, doubleClickZoom: true,
      boxZoom: true, keyboard: true
    });

    L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", {
      maxZoom: 19
    }).addTo(map);

    mapInstanceRef.current = map;

    // Force size recalculation after mount
    setTimeout(() => {
      map.invalidateSize({ animate: false });
      cargarOperarios();
    }, 200);
  }, []);

  // Update markers when operarios change
  useEffect(() => {
    const L = window.L;
    const map = mapInstanceRef.current;
    if (!L || !map || operarios.length === 0) return;

    // Remove old markers
    Object.values(markersRef.current).forEach(m => map.removeLayer(m));
    markersRef.current = {};

    const bounds = [];

    operarios.forEach(op => {
      if (!op.lat || !op.lng) return;
      const cfg = estadoConfig[op.ultima_marca] || estadoConfig["SIN MARCAR"];
      const color = cfg.color;
      const initials = (op.nombre || "??").split(" ").map(w => w[0]).join("").slice(0,2).toUpperCase();

      const iconHtml = `
        <div style="
          width:42px; height:42px; border-radius:50%;
          background:${color}; border:3px solid white;
          box-shadow:0 2px 12px ${color}80;
          display:flex; align-items:center; justify-content:center;
          font-weight:900; font-size:12px; color:white;
          font-family:sans-serif; position:relative;
          ${cfg.pulse ? `animation:pulse-marker 2s infinite;` : ""}
        ">
          ${initials}
          <div style="
            position:absolute; bottom:-4px; right:-4px;
            width:14px; height:14px; border-radius:50%;
            background:${color}; border:2px solid white;
          "></div>
        </div>
      `;

      const icon = L.divIcon({
        html: iconHtml, className: "", iconSize: [42, 42], iconAnchor: [21, 21]
      });

      const mins = op.timestamp ? Math.floor((Date.now() - new Date(op.timestamp)) / 60000) : null;
      const popup = L.popup({ maxWidth: 220, className: "apex-popup" }).setContent(`
        <div style="font-family:sans-serif; padding:4px;">
          <div style="font-weight:900; font-size:14px;">${op.nombre || op.username}</div>
          <div style="display:inline-block; padding:2px 8px; border-radius:10px;
            background:${color}20; color:${color}; font-size:11px; font-weight:700; margin:4px 0;">
            ${cfg.label}
          </div>
          ${op.ultima_hora ? `<div style="font-size:11px; color:#6B7A8D;">Ultima marca: ${op.ultima_hora}</div>` : ""}
          ${mins !== null ? `<div style="font-size:11px; color:#6B7A8D;">Actualizado hace ${mins < 1 ? "menos de 1 min" : mins + " min"}</div>` : ""}
          ${op.precision ? `<div style="font-size:10px; color:#94A3B8;">Precision: +/-${Math.round(op.precision)}m</div>` : ""}
          <div style="margin-top:8px;">
            <a href="https://www.google.com/maps?q=${op.lat},${op.lng}" target="_blank"
              style="font-size:11px; color:#00B4D8; text-decoration:none; font-weight:600;">
              Ver en Google Maps
            </a>
          </div>
        </div>
      `);

      const marker = L.marker([op.lat, op.lng], { icon }).addTo(map).bindPopup(popup);
      marker.on("click", () => setSelOp(op));
      markersRef.current[op.username] = marker;
      bounds.push([op.lat, op.lng]);
    });

    if (bounds.length > 0) {
      try { map.fitBounds(bounds, { padding: [40, 40], maxZoom: 15 }); } catch {}
    }
  }, [operarios]);

  // Auto refresh every 5 min
  useEffect(() => {
    const iv = setInterval(cargarOperarios, 5 * 60 * 1000);
    return () => clearInterval(iv);
  }, []);

  const activos = operarios.filter(o => ["INGRESO","RETORNO"].includes(o.ultima_marca));
  const enAlmuerzo = operarios.filter(o => o.ultima_marca === "ALMUERZO");
  const finalizados = operarios.filter(o => o.ultima_marca === "CIERRE");

  return (
    <div style={{ display:"flex", flexDirection:"column", gap:0 }}>

      {/* CSS animations */}
      <style>{`
        @keyframes pulse-marker {
          0%,100% { box-shadow: 0 2px 12px rgba(0,0,0,0.3); transform: scale(1); }
          50% { box-shadow: 0 4px 24px rgba(0,0,0,0.5); transform: scale(1.08); }
        }
        .leaflet-popup-content-wrapper {
          border-radius: 12px !important;
          box-shadow: 0 8px 32px rgba(0,0,0,0.15) !important;
        }
        .leaflet-popup-tip { display:none; }
      `}</style>

      {/* Mode toggle vivo / historico */}
      <div style={{ display:"flex", gap:8, marginBottom:14 }}>
        {[["vivo","EN VIVO"], ["historico","HISTORICO"]].map(([k,l]) => (
          <div key={k} onClick={() => { setModoMapa(k); limpiarHistorico(); limpiarRecorrido(); setTimeout(() => mapInstanceRef.current?.invalidateSize(), 100); }}
            style={{ padding:"7px 18px", borderRadius:20, cursor:"pointer",
              fontWeight:700, fontSize:12,
              background: modoMapa===k ? (k==="vivo" ? "#06D6A0" : "#8B5CF6") : C.bg,
              color: modoMapa===k ? "#fff" : C.muted,
              border:`1px solid ${modoMapa===k ? (k==="vivo" ? "#06D6A0" : "#8B5CF6") : C.border}` }}>
            {k==="vivo" && <span style={{marginRight:5}}>&#9679;</span>}
            {l}
          </div>
        ))}
      </div>

      {/* Filtros historico */}
      {modoMapa === "historico" && (
        <div style={{ background:C.card, border:`1px solid ${C.border}`, borderRadius:12,
          padding:"14px 16px", marginBottom:14 }}>
          <div style={{ fontSize:11, fontWeight:700, color:"#8B5CF6", marginBottom:10 }}>
            CONSULTA HISTORICA DE RECORRIDOS
          </div>
          <div style={{ display:"flex", gap:10, flexWrap:"wrap", alignItems:"flex-end" }}>
            <div>
              <div style={{ fontSize:10, fontWeight:700, color:C.muted, marginBottom:4 }}>FECHA</div>
              <input type="date" value={histFecha} onChange={e => setHistFecha(e.target.value)}
                style={{ padding:"8px 12px", border:`1px solid ${C.border}`, borderRadius:8, fontSize:13 }} />
            </div>
            <div>
              <div style={{ fontSize:10, fontWeight:700, color:C.muted, marginBottom:4 }}>OPERARIO</div>
              <select value={histNombre} onChange={e => setHistNombre(e.target.value)}
                style={{ padding:"8px 12px", border:`1px solid ${C.border}`, borderRadius:8, fontSize:13, background:C.bg, minWidth:160 }}>
                <option value="">Todos</option>
                {personal.map(p => <option key={p.nombre} value={p.nombre}>{p.nombre}</option>)}
              </select>
            </div>
            <div>
              <div style={{ fontSize:10, fontWeight:700, color:C.muted, marginBottom:4 }}>VEHICULO</div>
              <select value={histPlaca} onChange={e => setHistPlaca(e.target.value)}
                style={{ padding:"8px 12px", border:`1px solid ${C.border}`, borderRadius:8, fontSize:13, background:C.bg, minWidth:140 }}>
                <option value="">Todos</option>
                {vehiculos.map(v => <option key={v.placa} value={v.placa}>{v.placa}</option>)}
              </select>
            </div>
            <button onClick={buscarHistorico} disabled={histLoading}
              style={{ padding:"9px 20px", borderRadius:8, background:"#8B5CF6",
                color:"#fff", border:"none", fontWeight:700, fontSize:12, cursor:"pointer" }}>
              {histLoading ? "BUSCANDO..." : "BUSCAR"}
            </button>
            {histResultados.length > 0 && (
              <button onClick={limpiarHistorico}
                style={{ padding:"9px 16px", borderRadius:8, background:C.bg,
                  color:"#EF4444", border:`1px solid #EF444440`, fontWeight:700, fontSize:12, cursor:"pointer" }}>
                LIMPIAR
              </button>
            )}
          </div>
          {histResultados.length > 0 && (
            <div style={{ marginTop:12, display:"flex", gap:8, flexWrap:"wrap" }}>
              {histResultados.map((g, i) => (
                <div key={g.nombre} style={{ display:"flex", alignItems:"center", gap:6,
                  padding:"4px 10px", borderRadius:20, background:COLORES_OP[i%COLORES_OP.length]+"15",
                  border:`1px solid ${COLORES_OP[i%COLORES_OP.length]}40` }}>
                  <div style={{ width:10, height:10, borderRadius:"50%", background:COLORES_OP[i%COLORES_OP.length] }}/>
                  <span style={{ fontSize:11, fontWeight:700 }}>{g.nombre}</span>
                  <span style={{ fontSize:10, color:C.muted }}>{g.marcaciones.length} marcas</span>
                </div>
              ))}
            </div>
          )}
          {histResultados.length === 0 && !histLoading && (
            <div style={{ marginTop:8, fontSize:12, color:C.muted }}>
              Sin resultados. Selecciona fecha y filtros luego presiona Buscar.
            </div>
          )}
        </div>
      )}

      {/* KPI Bar - solo en vivo */}
      {modoMapa === "vivo" && <div style={{
        display:"flex", gap:12, padding:"12px 0", marginBottom:12, flexWrap:"wrap"
      }}>
        {[
          { label:"EN CAMPO", val:activos.length, color:"#06D6A0", icon:"[act]" },
          { label:"ALMUERZO", val:enAlmuerzo.length, color:"#F59E0B", icon:"[alm]" },
          { label:"FINALIZADO", val:finalizados.length, color:"#8B5CF6", icon:"[fin]" },
          { label:"RASTREADOS", val:operarios.length, color:"#00B4D8", icon:"[tot]" },
        ].map(k => (
          <div key={k.label} style={{
            flex:1, minWidth:100, padding:"10px 16px", borderRadius:10,
            background:`${k.color}10`, border:`1px solid ${k.color}30`,
            display:"flex", alignItems:"center", gap:10
          }}>
            <div style={{ fontSize:24, fontWeight:900, color:k.color }}>{k.val}</div>
            <div style={{ fontSize:10, fontWeight:700, color:k.color, lineHeight:1.3 }}>{k.label}</div>
          </div>
        ))}
        <div style={{ display:"flex", alignItems:"center", gap:8 }}>
          <div style={{
            width:10, height:10, borderRadius:"50%",
            background: gpsActivo ? "#06D6A0" : "#EF4444",
            boxShadow: gpsActivo ? "0 0 8px #06D6A0" : "none"
          }}/>
          <span style={{ fontSize:11, color:C.muted }}>
            {gpsActivo ? "Tu GPS activo" : gpsError || "GPS inactivo"}
          </span>
          {lastUpdate && (
            <span style={{ fontSize:10, color:C.muted }}>
              - Act: {lastUpdate.toLocaleTimeString()}
            </span>
          )}
          <button onClick={cargarOperarios}
            style={{ padding:"6px 12px", borderRadius:8, border:`1px solid ${C.border}`,
              background:C.bg, fontSize:11, cursor:"pointer", fontWeight:600 }}>
            {loading ? "..." : "ACTUALIZAR"}
          </button>
        </div>
      </div>}

      {/* Main content: sidebar + map */}
      <div style={{ display:"flex", gap:14, flex:1, minHeight:0 }}>

        {/* Sidebar operarios - solo en vivo */}
        {modoMapa === "vivo" && <div style={{
          width:260, flexShrink:0, display:"flex", flexDirection:"column", gap:8,
          overflowY:"auto", paddingRight:4
        }}>
          {operarios.length === 0 && !loading && (
            <div style={{ textAlign:"center", padding:40, color:C.muted }}>
              <div style={{ fontSize:32, marginBottom:8 }}>[radar]</div>
              <div style={{ fontSize:13 }}>Sin operarios rastreados hoy</div>
              <div style={{ fontSize:11, marginTop:4 }}>Los operarios deben tener GPS activo en su navegador</div>
            </div>
          )}
          {operarios.map(op => {
            const cfg = estadoConfig[op.ultima_marca] || estadoConfig["SIN MARCAR"];
            const mins = op.timestamp ? Math.floor((Date.now() - new Date(op.timestamp)) / 60000) : null;
            const isSelected = selOp?.username === op.username;
            return (
              <div key={op.username}
                onClick={() => {
                  setSelOp(op);
                  const map = mapInstanceRef.current;
                  const marker = markersRef.current[op.username];
                  if (map && marker) { map.setView([op.lat, op.lng], 15); marker.openPopup(); }
                  // Load recorrido
                  if (recorridoOp?.username === op.username) {
                    limpiarRecorrido(); setSelOp(null);
                  } else {
                    limpiarRecorrido();
                    cargarRecorrido(op);
                  }
                }}
                style={{
                  padding:"12px 14px", borderRadius:10, cursor:"pointer",
                  background: recorridoOp?.username === op.username ? cfg.color+"20" : isSelected ? cfg.color+"10" : C.card,
                  border:`1px solid ${isSelected ? cfg.color : C.border}`,
                  transition:"all 0.2s"
                }}>
                <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                  <div style={{
                    width:38, height:38, borderRadius:"50%", flexShrink:0,
                    background:cfg.color+"20", border:`2px solid ${cfg.color}`,
                    display:"flex", alignItems:"center", justifyContent:"center",
                    fontWeight:900, fontSize:12, color:cfg.color
                  }}>
                    {(op.nombre||"??").split(" ").map(w=>w[0]).join("").slice(0,2).toUpperCase()}
                  </div>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ fontWeight:700, fontSize:13, whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis" }}>
                      {op.nombre || op.username}
                    </div>
                    <div style={{ fontSize:10, fontWeight:700, color:cfg.color }}>{cfg.label}</div>
                  </div>
                  <div style={{
                    width:8, height:8, borderRadius:"50%", background:cfg.color, flexShrink:0,
                    boxShadow: cfg.pulse ? `0 0 6px ${cfg.color}` : "none"
                  }}/>
                </div>
                {mins !== null && (
                  <div style={{ fontSize:10, color:C.muted, marginTop:6, paddingLeft:48 }}>
                    Hace {mins < 1 ? "menos de 1 min" : `${mins} min`}
                  </div>
                )}
                {recorridoOp?.username === op.username && recorrido.length > 0 && (
                  <div style={{ marginTop:8, paddingTop:8, borderTop:`1px solid ${cfg.color}30` }}>
                    <div style={{ fontSize:9, fontWeight:700, color:cfg.color, marginBottom:4 }}>
                      RECORRIDO HOY - {recorrido.length} MARCACION(ES)
                    </div>
                    {recorrido.map((r, i) => {
                      const mc = MARCA_CONFIG[r.tipo] || { color:"#94A3B8", label:r.tipo };
                      return (
                        <div key={i} style={{ display:"flex", alignItems:"center", gap:6, marginBottom:3 }}>
                          <div style={{ width:16, height:16, borderRadius:"50%", background:mc.color,
                            display:"flex", alignItems:"center", justifyContent:"center",
                            fontSize:9, color:"white", fontWeight:700, flexShrink:0 }}>{i+1}</div>
                          <div style={{ fontSize:10 }}>
                            <span style={{ color:mc.color, fontWeight:700 }}>{mc.label}</span>
                            <span style={{ color:C.muted }}> {r.hora}</span>
                          </div>
                        </div>
                      );
                    })}
                    <div onClick={(e) => { e.stopPropagation(); limpiarRecorrido(); setSelOp(null); }}
                      style={{ marginTop:6, fontSize:10, color:"#EF4444", cursor:"pointer", fontWeight:600 }}>
                      Ocultar recorrido
                    </div>
                  </div>
                )}
                {recorridoOp?.username === op.username && recorrido.length === 0 && (
                  <div style={{ fontSize:10, color:C.muted, marginTop:6, fontStyle:"italic" }}>
                    Sin marcaciones GPS registradas hoy
                  </div>
                )}
              </div>
            );
          })}
        </div>}

        {/* Mapa */}
        <div style={{ flex:1, borderRadius:14, overflow:"hidden", border:`1px solid ${C.border}`,
          position:"relative", minHeight:500, height:500 }}>
          <div ref={mapRef} style={{ width:"100%", height:"500px", position:"absolute", top:0, left:0 }} />
          {operarios.length === 0 && (
            <div style={{
              position:"absolute", inset:0, display:"flex", flexDirection:"column",
              alignItems:"center", justifyContent:"center",
              background:"rgba(13,27,42,0.7)", color:"white", borderRadius:14
            }}>
              <div style={{ fontSize:48, marginBottom:12 }}>[sat]</div>
              <div style={{ fontSize:16, fontWeight:700 }}>Sin senales GPS activas</div>
              <div style={{ fontSize:12, opacity:0.7, marginTop:4 }}>
                Esperando que los operarios activen su ubicacion
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};


const Horarios = ({ onBack, user }) => {
  const [vista, setVista] = useState("menu");
  const [rutas, setRutas] = useState([]);
  const [personal, setPersonal] = useState([]);
  const [vehiculos, setVehiculos] = useState([]);
  const [novedadesTipo, setNovedadesTipo] = useState([]);
  const [loading, setLoading] = useState(false);
  const [msg, setMsg] = useState(null);

  // Estado marcacion
  const [marcForm, setMarcForm] = useState({
    usuario: user?.nombre || user?.username || "",
    vehiculo_placa: "",
    tipo_marca: "",
    latitud: null, longitud: null,
    ruta_id: null,
    novedad_tipo_id: null,
    novedad_descripcion: ""
  });
  const [showNovedad, setShowNovedad] = useState(false);
  const [resultMarca, setResultMarca] = useState(null);
  const [ultimaMarca, setUltimaMarca] = useState(null);

  const ORDEN_MARCAS = ["INGRESO","ALMUERZO","RETORNO","CIERRE"];
  const marcaHabilitada = (tipo) => {
    if (!ultimaMarca) return tipo === "INGRESO";
    const idxUlt = ORDEN_MARCAS.indexOf(ultimaMarca);
    if (idxUlt === -1) return tipo === "INGRESO";
    return ORDEN_MARCAS.indexOf(tipo) === idxUlt + 1;
  };
  const marcaRealizada = (tipo) => {
    if (!ultimaMarca) return false;
    const idxUlt = ORDEN_MARCAS.indexOf(ultimaMarca);
    return ORDEN_MARCAS.indexOf(tipo) <= idxUlt;
  };
  // Estado planeacion
  const [rutaForm, setRutaForm] = useState({
    fecha: new Date(new Date().getTime() - new Date().getTimezoneOffset() * 60000).toISOString().split("T")[0],
    placa: "", empleados: [], h_inicio: "06:00", h_fin: "14:00",
    viaticos: 0, tolerancia_minutos: 15
  });
  const [empSeleccionados, setEmpSeleccionados] = useState([]);

  // Estado monitor
  const [monitorRutas, setMonitorRutas] = useState([]);
  const [monitorFecha, setMonitorFecha] = useState(new Date(new Date().getTime() - new Date().getTimezoneOffset() * 60000).toISOString().split("T")[0]);
  const [monitorInterval, setMonitorInterval] = useState(null);
  const [vistaMonitor, setVistaMonitor] = useState("monitor");
  const [filtroPlaca, setFiltroPlaca] = useState("");
  const [filtroOperario, setFiltroOperario] = useState("");
  const [filtroEstado, setFiltroEstado] = useState("");
  const [filtroRutaId, setFiltroRutaId] = useState("");

  const [rutasHoy, setRutasHoy] = useState([]);

  useEffect(() => {
    fetch(`${API_URL}/personal`).then(r=>r.json()).then(d => setPersonal(Array.isArray(d) ? d : [])).catch(()=>{});
    fetch(`${API_URL}/vehiculos`).then(r=>r.json()).then(d => setVehiculos(Array.isArray(d) ? d : [])).catch(()=>{});
    fetch(`${API_URL}/novedades-tipo`).then(r=>r.json()).then(setNovedadesTipo).catch(()=>{});
    // Cargar rutas de hoy
    const hoy = new Date(new Date().getTime() - new Date().getTimezoneOffset() * 60000).toISOString().split("T")[0];
    fetch(`${API_URL}/monitor/rutas?fecha=${hoy}`)
      .then(r=>r.json()).then(data => setRutasHoy(data)).catch(()=>{});
    // Cargar ultima marcacion del dia para este usuario
    const nombreUsuario = user?.nombre || user?.username || "";
    if (nombreUsuario) {
      fetch(`${API_URL}/asistencia/detalle?fecha=${hoy}&usuario=${encodeURIComponent(nombreUsuario)}`)
        .then(r=>r.json())
        .then(data => {
          if (data && data.length > 0) {
            const ultima = data[data.length - 1];
            setUltimaMarca(ultima.tipo_marca);
            // Restaurar vehiculo si hay marcacion previa
            if (ultima.placa) {
              setMarcForm(f => ({ ...f, vehiculo_placa: ultima.placa }));
            }
          }
        }).catch(()=>{});
    }
  }, []);

  useEffect(() => {
    if (vista === "monitor") cargarMonitor();
  }, [vista, monitorFecha]);

  const cargarMonitor = async () => {
    try {
      const r = await fetch(`${API_URL}/monitor/rutas?fecha=${monitorFecha}`);
      const data = await r.json();
      setMonitorRutas(data);
    } catch(e) {}
  };

  const obtenerGPS = () => new Promise((res) => {
    if (!navigator.geolocation) { res(null); return; }
    navigator.geolocation.getCurrentPosition(
      (pos) => res({ lat: pos.coords.latitude, lon: pos.coords.longitude }),
      () => res(null),
      { timeout: 8000 }
    );
  });

  const realizarMarcacion = async (tipo) => {
    setLoading(true);
    setMsg(null);
    const gps = await obtenerGPS();
    const payload = {
      ...marcForm,
      tipo_marca: tipo,
      latitud: gps?.lat || null,
      longitud: gps?.lon || null,
    };
    try {
      const r = await fetch(`${API_URL}/marcaciones`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload)
      });
      const data = await r.json();
      setResultMarca({ ...data, tipo, gps });
      setUltimaMarca(tipo);
      if (data.alerta) setShowNovedad(true);
      else setMsg({ tipo: "ok", texto: `${tipo} registrado a las ${data.hora}${gps ? " con GPS" : " sin GPS"}` });
    } catch(e) {
      setMsg({ tipo: "error", texto: "Error al registrar marcacion" });
    }
    setLoading(false);
  };

  const guardarNovedad = async () => {
    if (!marcForm.novedad_tipo_id) { setMsg({ tipo: "error", texto: "Selecciona un motivo" }); return; }
    setLoading(true);
    try {
      const r = await fetch(`${API_URL}/marcaciones`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...marcForm,
          tipo_marca: resultMarca?.tipo || "CIERRE",
          latitud: resultMarca?.gps?.lat || null,
          longitud: resultMarca?.gps?.lon || null,
        })
      });
      const data = await r.json();
      setShowNovedad(false);
      setMsg({ tipo: "ok", texto: `Marcacion con novedad registrada. Hora extra: ${resultMarca?.minutos_extra || 0} min` });
    } catch(e) {
      setMsg({ tipo: "error", texto: "Error guardando novedad" });
    }
    setLoading(false);
  };

  const crearRuta = async () => {
    if (!rutaForm.placa || empSeleccionados.length === 0) {
      setMsg({ tipo: "error", texto: "Completa vehiculo y empleados" }); return;
    }
    setLoading(true);
    try {
      const r = await fetch(`${API_URL}/rutas`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...rutaForm, empleados: empSeleccionados })
      });
      const data = await r.json();
      if (data.ok) {
        setMsg({ tipo: "ok", texto: "Ruta creada correctamente" });
        setRutaForm({ fecha: new Date(new Date().getTime() - new Date().getTimezoneOffset() * 60000).toISOString().split("T")[0], placa: "", empleados: [], h_inicio: "06:00", h_fin: "14:00", viaticos: 0, tolerancia_minutos: 15 });
        setEmpSeleccionados([]);
      }
    } catch(e) {
      setMsg({ tipo: "error", texto: "Error creando ruta" });
    }
    setLoading(false);
  };

  const toggleEmpleado = (nombre) => {
    setEmpSeleccionados(prev =>
      prev.includes(nombre) ? prev.filter(e => e !== nombre) : [...prev, nombre]
    );
  };

  const MARCAS = [
    { tipo: "INGRESO",  label: "Inicio de Jornada", color: "#06D6A0", desc: "Registrar llegada al punto de trabajo" },
    { tipo: "ALMUERZO", label: "Salida Almuerzo",   color: "#F59E0B", desc: "Registrar inicio de descanso" },
    { tipo: "RETORNO",  label: "Retorno Labores",   color: "#00B4D8", desc: "Registrar regreso al trabajo" },
    { tipo: "CIERRE",   label: "Cierre de Jornada", color: "#8B5CF6", desc: "Registrar fin de turno" },
  ];

  const estadoColor = { "INGRESO": "#06D6A0", "ALMUERZO": "#F59E0B", "RETORNO": "#00B4D8", "CIERRE": "#8B5CF6", "SIN MARCAR": "#8892A4" };
  const estadoLabel = { "INGRESO": "En Jornada", "ALMUERZO": "En Almuerzo", "RETORNO": "Trabajando", "CIERRE": "Finalizo", "SIN MARCAR": "Sin Iniciar" };

  const fmtMin = (min) => {
    if (!min) return "--";
    const h = Math.floor(min / 60);
    const m = min % 60;
    return h > 0 ? `${h}h ${m}m` : `${m}m`;
  };

  // ---- MENU PRINCIPAL ----
  if (vista === "menu") return (
    <div>
      <PageHeader title="Control de Horarios" subtitle="Gestion de tiempos y rutas" onBack={onBack} />
      {msg && <Alert tipo={msg.tipo} texto={msg.texto} onClose={() => setMsg(null)} />}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(220px, 1fr))", gap: 16 }}>
        {[
          { id: "marcacion", label: "Marcacion", desc: "Registrar ingreso, almuerzo, retorno o cierre", color: "#06D6A0" },
          { id: "planeacion", label: "Planeacion de Rutas", desc: "Crear y asignar rutas del dia o semana", color: "#00B4D8" },
          { id: "monitor", label: "Monitor en Vivo", desc: "Ver estado actual de todas las rutas", color: "#F59E0B" },
        ].map(item => (
          <Card key={item.id} onClick={() => setVista(item.id)} style={{ cursor: "pointer", borderBottom: `3px solid ${item.color}` }}>
            <div style={{
              width: 44, height: 44, borderRadius: 12, marginBottom: 12,
              background: item.color + "18", border: `1px solid ${item.color}30`,
              display: "flex", alignItems: "center", justifyContent: "center"
            }}>
              <div style={{ width: 16, height: 16, borderRadius: "50%", background: item.color }} />
            </div>
            <div style={{ fontWeight: 700, marginBottom: 4 }}>{item.label}</div>
